/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const N = nums.length;
    const INF = Number.MAX_SAFE_INTEGER / 2;

    if (k === 0) {
        return 0;
    }

    // Maximum possible peaks is floor(N/2)
    if (k > Math.floor(N / 2)) {
        return -1;
    }

    // --- Step 0: Calculate Costs C[i] ---
    const C = new Array(N);
    for (let i = 0; i < N; i++) {
        const prevIndex = (i - 1 + N) % N;
        const nextIndex = (i + 1) % N;

        const L = nums[prevIndex];
        const R = nums[nextIndex];

        // Required value > max(L, R)
        const requiredValue = Math.max(L, R) + 1;

        // Cost = max(0, requiredValue - nums[i])
        C[i] = Math.max(0, requiredValue - nums[i]);
    }

    // --- Step 2: Handle Small N ---
    if (N === 2) {
        // k must be 1 here
        return Math.min(C[0], C[1]);
    }
    if (N === 3) {
        // k must be 1 here
        return Math.min(C[0], C[1], C[2]);
    }

    // --- Step 3: General DP (N >= 4) ---

    let minCost = INF;

    // --- Case A: Index 0 is NOT selected. Path 1 to N-1. Length L = N-1. Target k. ---
    const L_A = N - 1;
    // DP_A[i][j][s]: Min cost using j peaks from indices 1..i. i=0 means index 1.
    // i runs from 0 to L_A - 1 (representing cycle indices 1 to N-1)
    // j runs from 0 to k
    // s=0: index i NOT selected; s=1: index i IS selected

    // Initialize DP_A table: (N-1) length + 1 index for padding, (k+1) target + 1 index for padding, 2 states
    const dpA = Array(L_A).fill(0).map(() => 
        Array(k + 1).fill(0).map(() => [INF, INF])
    );

    // Base Case i = 1 (DP index 0)
    dpA[0][0][0] = 0;
    dpA[0][1][1] = C[1];

    for (let i = 1; i < L_A; i++) { // i corresponds to cycle index i+1
        const cycleIndex = i + 1;
        for (let j = 0; j <= k; j++) {
            // Case s=0: Current element (cycleIndex) not selected
            dpA[i][j][0] = Math.min(dpA[i-1][j][0], dpA[i-1][j][1]);

            // Case s=1: Current element (cycleIndex) selected
            if (j >= 1) {
                // Must come from i-1 not selected
                const costIfSelected = dpA[i-1][j-1][0] + C[cycleIndex];
                dpA[i][j][1] = costIfSelected;
            }
        }
    }

    const resultA = Math.min(dpA[L_A - 1][k][0], dpA[L_A - 1][k][1]);
    minCost = Math.min(minCost, resultA);


    // --- Case B: Index 0 IS selected. Path 2 to N-2. Length L = N-3. Target k-1. ---
    if (k >= 1) {
        const L_B = N - 3;
        const targetK = k - 1;

        // DP_B[i'][j][s]: Min cost using j peaks from indices 2..i'+2.
        // i' runs from 0 to L_B - 1 (representing cycle indices 2 to N-2)

        const dpB = Array(L_B).fill(0).map(() => 
            Array(targetK + 1).fill(0).map(() => [INF, INF])
        );

        // Base Case i' = 0 (Cycle index 2)
        dpB[0][0][0] = 0;
        dpB[0][1][1] = C[2];

        for (let i_prime = 1; i_prime < L_B; i_prime++) { 
            const cycleIndex = i_prime + 2;
            for (let j = 0; j <= targetK; j++) {
                // Case s=0: Current element not selected
                dpB[i_prime][j][0] = Math.min(dpB[i_prime-1][j][0], dpB[i_prime-1][j][1]);

                // Case s=1: Current element selected
                if (j >= 1) {
                    // Must come from i'-1 not selected
                    const costIfSelected = dpB[i_prime-1][j-1][0] + C[cycleIndex];
                    dpB[i_prime][j][1] = costIfSelected;
                }
            }
        }

        const pathCostB = Math.min(dpB[L_B - 1][targetK][0], dpB[L_B - 1][targetK][1]);
        const resultB = C[0] + pathCostB;
        minCost = Math.min(minCost, resultB);
    }


    return minCost === INF ? -1 : minCost;
}

