// solve finds the minimum operations needed to achieve at least k peaks in a circular array nums.
func solve(nums []int64, k int64) int64 {
	N := len(nums)
	INF := int64(math.MaxInt64 / 2)

	if k == 0 {
		return 0
	}

	// Maximum possible peaks is floor(N/2)
	if k*2 > int64(N) {
		return -1
	}

	// --- Step 0: Calculate Costs C[i] ---
	C := make([]int64, N)
	for i := 0; i < N; i++ {
		prevIndex := (i - 1 + N) % N
		nextIndex := (i + 1) % N

		L := nums[prevIndex]
		R := nums[nextIndex]

		// Required value > max(L, R)
		requiredValue := int64(math.Max(float64(L), float64(R))) + 1

		// Cost = max(0, requiredValue - nums[i])
		cost := requiredValue - nums[i]
		if cost < 0 {
			cost = 0
		}
		C[i] = cost
	}

	// --- Step 2: Handle Small N ---
	if N == 2 {
		// k must be 1 here (checked by k*2 > N)
		return min(C[0], C[1])
	}
	if N == 3 {
		// k must be 1 here
		return min(C[0], C[1], C[2])
	}

	minCost := INF

	// --- Case A: Index 0 is NOT selected. Path 1 to N-1. Length L = N-1. Target k. ---
	LA := N - 1
	// dpA[i][j][s]: Min cost using j peaks from indices 1..i+1. i runs 0 to LA-1.
	// s=0: index i+1 NOT selected; s=1: index i+1 IS selected
	dpA := make([][][]int64, LA)
	for i := range dpA {
		dpA[i] = make([][]int64, k+1)
		for j := range dpA[i] {
			dpA[i][j] = []int64{INF, INF}
		}
	}

	// Base Case i = 1 (DP index 0)
	dpA[0][0][0] = 0
	dpA[0][1][1] = C[1]

	for i := 1; i < LA; i++ { // i corresponds to cycle index i+1
		cycleIndex := i + 1
		for j := 0; j <= int(k); j++ {
			// Case s=0: Current element (cycleIndex) not selected
			dpA[i][j][0] = min(dpA[i-1][j][0], dpA[i-1][j][1])

			// Case s=1: Current element (cycleIndex) selected
			if j >= 1 {
				// Must come from i-1 not selected
				costIfSelected := dpA[i-1][j-1][0] + C[cycleIndex]
				dpA[i][j][1] = costIfSelected
			}
		}
	}

	resultA := min(dpA[LA-1][int(k)][0], dpA[LA-1][int(k)][1])
	minCost = min(minCost, resultA)

	// --- Case B: Index 0 IS selected. Path 2 to N-2. Length L = N-3. Target k-1. ---
	if k >= 1 {
		targetK := k - 1
		LB := N - 3

		dpB := make([][][]int64, LB)
		for i := range dpB {
			dpB[i] = make([][]int64, targetK+1)
			for j := range dpB[i] {
				dpB[i][j] = []int64{INF, INF}
			}
		}

		// Base Case i = 2 (DP index 0)
		dpB[0][0][0] = 0
		dpB[0][1][1] = C[2]

		for iPrime := 1; iPrime < LB; iPrime++ {
			cycleIndex := iPrime + 2
			for j := 0; j <= int(targetK); j++ {
				// Case s=0: Current element not selected
				dpB[iPrime][j][0] = min(dpB[iPrime-1][j][0], dpB[iPrime-1][j][1])

				// Case s=1: Current element selected
				if j >= 1 {
					// Must come from i'-1 not selected
					costIfSelected := dpB[iPrime-1][j-1][0] + C[cycleIndex]
					dpB[iPrime][j][1] = costIfSelected
				}
			}
		}

		pathCostB := min(dpB[LB-1][int(targetK)][0], dpB[LB-1][int(targetK)][1])
		resultB := C[0] + pathCostB
		minCost = min(minCost, resultB)
	}

	if minCost == INF {
		return -1
	}
	return minCost
}

func min(a int64, b int64) int64 {
	if a < b {
		return a
	}
	return b
}

func min3(a, b, c int64) int64 {
	return min(a, min(b, c))
}
